import vex
import smolagents

vex_policies = {
    "tenant-isolation": {
        "rules": [
            "input.tenant_id == context.tenant_id",
            "!output.contains('other_tenant')"
        ]
    },
    "eu-data-residency": {
        "rules": [
            "if tenant.region == 'EU' then !uses_tool('us-vector-search')"
        ]
    }
}

@vex.verify(policies=vex_policies)
def enterprise_agent_run(task: str, tenant: dict):
    agent = smolagents.ToolAgent(tools=tenant['approved_tools'])
    return agent.run(task)
